//! Code generator: produces `gen_tablegen.rs` from build-time extraction output.
//!
//! The generated file defines `load_from_generated() -> TblgenOutput` which
//! constructs the same data structure as the former `load_full_via_tblgen()`,
//! but from compiled-in constants instead of runtime LLVM linkage.

use std::fmt::Write;
use std::path::Path;

use super::extract::*;
use super::records::BuildInstrEncoding;

/// Generate the `gen_tablegen.rs` file in `$OUT_DIR`.
pub fn generate_tablegen_file(output: &BuildTblgenOutput, out_dir: &Path) {
    let mut code = String::with_capacity(2 * 1024 * 1024); // ~2MB estimate

    writeln!(code, "// Auto-generated by build.rs -- do not edit.").unwrap();
    writeln!(code, "// Source: llvm-aie TableGen extraction at build time.").unwrap();
    writeln!(code).unwrap();
    writeln!(code, "/// Load instruction decoder data from build-time extracted constants.").unwrap();
    writeln!(code, "pub(crate) fn load_from_generated() -> super::types::TblgenOutput {{").unwrap();
    writeln!(code, "    use super::types::*;").unwrap();
    writeln!(code, "    use super::resolver::*;").unwrap();
    writeln!(code, "    use super::decoder_bytecode::DecoderTable;").unwrap();
    writeln!(code, "    use std::collections::HashMap;").unwrap();
    writeln!(code).unwrap();

    // Encodings by slot
    writeln!(code, "    let mut encodings_by_slot: HashMap<String, Vec<InstrEncoding>> = HashMap::new();").unwrap();
    let mut slot_names: Vec<&String> = output.encodings_by_slot.keys().collect();
    slot_names.sort();
    for slot in &slot_names {
        let encodings = &output.encodings_by_slot[*slot];
        writeln!(code, "    encodings_by_slot.insert({:?}.to_string(), vec![", slot).unwrap();
        for enc in encodings {
            format_encoding(&mut code, enc);
        }
        writeln!(code, "    ]);").unwrap();
    }

    // Processor model
    writeln!(code).unwrap();
    if let Some(ref model) = output.processor_model {
        writeln!(code, "    let processor_model = Some(ProcessorModel {{").unwrap();
        writeln!(code, "        load_latency: {},", model.load_latency).unwrap();
        writeln!(code, "        high_latency: {},", model.high_latency).unwrap();
        writeln!(code, "        mispredict_penalty: {},", model.mispredict_penalty).unwrap();
        writeln!(code, "        issue_width: {},", model.issue_width).unwrap();
        writeln!(code, "        itinerary_name: {:?}.to_string(),", model.itinerary_name).unwrap();
        writeln!(code, "    }});").unwrap();
    } else {
        writeln!(code, "    let processor_model: Option<ProcessorModel> = None;").unwrap();
    }

    // Itineraries
    writeln!(code).unwrap();
    writeln!(code, "    let mut itineraries: HashMap<String, ItineraryInfo> = HashMap::new();").unwrap();
    let mut itin_names: Vec<&String> = output.itineraries.keys().collect();
    itin_names.sort();
    for name in &itin_names {
        let info = &output.itineraries[*name];
        format_itinerary(&mut code, info);
    }

    // Register model
    writeln!(code).unwrap();
    writeln!(code, "    let mut reg_registers: HashMap<String, RegisterDef> = HashMap::new();").unwrap();
    let mut reg_names: Vec<&String> = output.register_model.registers.keys().collect();
    reg_names.sort();
    for name in &reg_names {
        let reg = &output.register_model.registers[*name];
        writeln!(code, "    reg_registers.insert({:?}.to_string(), RegisterDef {{", name).unwrap();
        writeln!(code, "        name: {:?}.to_string(),", reg.name).unwrap();
        writeln!(code, "        hw_encoding: {},", reg.hw_encoding).unwrap();
        writeln!(code, "        parents: vec![{}],", reg.parents.iter().map(|p| format!("{:?}.to_string()", p)).collect::<Vec<_>>().join(", ")).unwrap();
        writeln!(code, "    }});").unwrap();
    }

    writeln!(code).unwrap();
    writeln!(code, "    let mut reg_classes: HashMap<String, RegisterClassDef> = HashMap::new();").unwrap();
    let mut class_names: Vec<&String> = output.register_model.classes.keys().collect();
    class_names.sort();
    for name in &class_names {
        let cls = &output.register_model.classes[*name];
        writeln!(code, "    reg_classes.insert({:?}.to_string(), RegisterClassDef {{", name).unwrap();
        writeln!(code, "        name: {:?}.to_string(),", cls.name).unwrap();
        writeln!(code, "        members: vec![{}],", cls.members.iter().map(|m| format!("{:?}.to_string()", m)).collect::<Vec<_>>().join(", ")).unwrap();
        writeln!(code, "        alignment: {},", cls.alignment).unwrap();
        writeln!(code, "        parents: vec![{}],", cls.parents.iter().map(|p| format!("{:?}.to_string()", p)).collect::<Vec<_>>().join(", ")).unwrap();
        writeln!(code, "    }});").unwrap();
    }

    writeln!(code).unwrap();
    writeln!(code, "    let register_model = RegisterModel {{ registers: reg_registers, classes: reg_classes }};").unwrap();

    // Composite formats
    writeln!(code).unwrap();
    writeln!(code, "    let composite_formats = vec![").unwrap();
    for fmt in &output.composite_formats {
        format_composite(&mut code, fmt);
    }
    writeln!(code, "    ];").unwrap();

    // Decoder tables
    writeln!(code).unwrap();
    writeln!(code, "    let mut decoder_tables: HashMap<String, DecoderTable> = HashMap::new();").unwrap();
    let mut dt_names: Vec<&String> = output.decoder_tables.keys().collect();
    dt_names.sort();
    for name in &dt_names {
        let table = &output.decoder_tables[*name];
        format_decoder_table(&mut code, name, table);
    }

    // Return
    writeln!(code).unwrap();
    writeln!(code, "    TblgenOutput {{").unwrap();
    writeln!(code, "        encodings_by_slot,").unwrap();
    writeln!(code, "        processor_model,").unwrap();
    writeln!(code, "        itineraries,").unwrap();
    writeln!(code, "        register_model,").unwrap();
    writeln!(code, "        composite_formats,").unwrap();
    writeln!(code, "        decoder_tables,").unwrap();
    writeln!(code, "    }}").unwrap();
    writeln!(code, "}}").unwrap();

    std::fs::write(out_dir.join("gen_tablegen.rs"), &code).unwrap();
    eprintln!(
        "cargo:warning=Generated gen_tablegen.rs: {} bytes",
        code.len()
    );
}

// ---------------------------------------------------------------------------
// Formatting helpers
// ---------------------------------------------------------------------------

fn format_encoding(code: &mut String, enc: &BuildInstrEncoding) {
    writeln!(code, "        InstrEncoding {{").unwrap();
    writeln!(code, "            name: {:?}.to_string(),", enc.name).unwrap();
    writeln!(code, "            mnemonic: {:?}.to_string(),", enc.mnemonic).unwrap();
    writeln!(code, "            slot: {:?}.to_string(),", enc.slot).unwrap();
    writeln!(code, "            width: {},", enc.width).unwrap();
    writeln!(code, "            fixed_mask: 0x{:X},", enc.fixed_mask).unwrap();
    writeln!(code, "            fixed_bits: 0x{:X},", enc.fixed_bits).unwrap();

    // Operand fields
    writeln!(code, "            operand_fields: vec![").unwrap();
    for field in &enc.operand_fields {
        format_operand_field(code, field);
    }
    writeln!(code, "            ],").unwrap();

    // Semantic
    match &enc.semantic {
        Some(s) => writeln!(code, "            semantic: Some({}),", s).unwrap(),
        None => writeln!(code, "            semantic: None,").unwrap(),
    }

    writeln!(code, "            may_load: {},", enc.may_load).unwrap();
    writeln!(code, "            may_store: {},", enc.may_store).unwrap();

    // Input/output order
    writeln!(code, "            input_order: vec![{}],",
        enc.input_order.iter().map(|n| format!("{:?}.to_string()", n)).collect::<Vec<_>>().join(", ")).unwrap();
    writeln!(code, "            output_order: vec![{}],",
        enc.output_order.iter().map(|n| format!("{:?}.to_string()", n)).collect::<Vec<_>>().join(", ")).unwrap();

    // Implicit regs
    writeln!(code, "            implicit_regs: vec![").unwrap();
    for reg in &enc.implicit_regs {
        writeln!(code, "                ImplicitReg {{ reg_class: {:?}.to_string(), reg_num: {}, is_use: {} }},",
            reg.reg_class, reg.reg_num, reg.is_use).unwrap();
    }
    writeln!(code, "            ],").unwrap();

    writeln!(code, "            addressing_mode: {},", enc.addressing_mode).unwrap();
    writeln!(code, "            mem_width: {},", enc.mem_width).unwrap();
    writeln!(code, "            has_complete_decoder: {},", enc.has_complete_decoder).unwrap();

    match &enc.element_type {
        Some(s) => writeln!(code, "            element_type: Some({}),", s).unwrap(),
        None => writeln!(code, "            element_type: None,").unwrap(),
    }
    match &enc.branch_condition {
        Some(s) => writeln!(code, "            branch_condition: Some({}),", s).unwrap(),
        None => writeln!(code, "            branch_condition: None,").unwrap(),
    }
    writeln!(code, "            is_vector: {},", enc.is_vector).unwrap();
    match &enc.select_variant {
        Some(s) => writeln!(code, "            select_variant: Some({}),", s).unwrap(),
        None => writeln!(code, "            select_variant: None,").unwrap(),
    }
    writeln!(code, "            is_ptr_arithmetic: {},", enc.is_ptr_arithmetic).unwrap();
    writeln!(code, "            is_sp_relative: {},", enc.is_sp_relative).unwrap();
    match &enc.sched_class {
        Some(s) => writeln!(code, "            sched_class: Some({:?}.to_string()),", s).unwrap(),
        None => writeln!(code, "            sched_class: None,").unwrap(),
    }
    writeln!(code, "        }},").unwrap();
}

fn format_operand_field(code: &mut String, field: &super::records::BuildOperandField) {
    writeln!(code, "                {{").unwrap();
    writeln!(code, "                    let mut f = OperandField::new({:?}, {}, {});", field.name, field.bit_position, field.width).unwrap();
    writeln!(code, "                    f.signed = {};", field.signed).unwrap();
    writeln!(code, "                    f.operand_type = {};", field.operand_type).unwrap();
    writeln!(code, "                    f.is_output = {};", field.is_output).unwrap();
    if !field.fragments.is_empty() {
        writeln!(code, "                    f.fragments = vec![").unwrap();
        for frag in &field.fragments {
            writeln!(code, "                        FieldFragment {{ inst_bit: {}, width: {}, target_bit: {} }},",
                frag.inst_bit, frag.width, frag.target_bit).unwrap();
        }
        writeln!(code, "                    ];").unwrap();
    }
    writeln!(code, "                    f").unwrap();
    writeln!(code, "                }},").unwrap();
}

fn format_itinerary(code: &mut String, info: &BuildItineraryInfo) {
    writeln!(code, "    itineraries.insert({:?}.to_string(), ItineraryInfo {{", info.class_name).unwrap();
    writeln!(code, "        class_name: {:?}.to_string(),", info.class_name).unwrap();
    writeln!(code, "        total_latency: {},", info.total_latency).unwrap();
    writeln!(code, "        operand_cycles: vec![{}],",
        info.operand_cycles.iter().map(|c| c.to_string()).collect::<Vec<_>>().join(", ")).unwrap();
    writeln!(code, "        stages: vec![").unwrap();
    for stage in &info.stages {
        writeln!(code, "            PipelineStage {{ cycles: {}, units: vec![{}], time_inc: {} }},",
            stage.cycles,
            stage.units.iter().map(|u| format!("{:?}.to_string()", u)).collect::<Vec<_>>().join(", "),
            stage.time_inc).unwrap();
    }
    writeln!(code, "        ],").unwrap();
    writeln!(code, "        bypasses: vec![{}],",
        info.bypasses.iter().map(|b| format!("{:?}.to_string()", b)).collect::<Vec<_>>().join(", ")).unwrap();
    writeln!(code, "    }});").unwrap();
}

fn format_composite(code: &mut String, fmt: &BuildCompositeFormat) {
    writeln!(code, "        CompositeFormatDef {{").unwrap();
    writeln!(code, "            name: {:?}.to_string(),", fmt.name).unwrap();
    writeln!(code, "            total_bytes: {},", fmt.total_bytes).unwrap();
    writeln!(code, "            total_bits: {},", fmt.total_bits).unwrap();
    writeln!(code, "            slots: vec![{}],",
        fmt.slots.iter().map(|(n, w)| format!("({:?}.to_string(), {})", n, w)).collect::<Vec<_>>().join(", ")).unwrap();
    writeln!(code, "            fixed_mask: 0x{:X},", fmt.fixed_mask).unwrap();
    writeln!(code, "            fixed_value: 0x{:X},", fmt.fixed_value).unwrap();
    writeln!(code, "            slot_maps: vec![").unwrap();
    for sm in &fmt.slot_maps {
        writeln!(code, "                SlotBitMap {{ slot_name: {:?}.to_string(), width: {}, start_bit: {} }},",
            sm.slot_name, sm.width, sm.start_bit).unwrap();
    }
    writeln!(code, "            ],").unwrap();
    writeln!(code, "        }},").unwrap();
}

fn format_decoder_table(
    code: &mut String,
    slot_name: &str,
    table: &super::bytecode::BuildDecoderTable,
) {
    writeln!(code, "    {{").unwrap();
    // Format bytes as a vec![...] with 16 bytes per line
    writeln!(code, "        let bytes: Vec<u8> = vec![").unwrap();
    for chunk in table.bytes.chunks(16) {
        let hex: Vec<String> = chunk.iter().map(|b| format!("0x{:02X}", b)).collect();
        writeln!(code, "            {},", hex.join(", ")).unwrap();
    }
    writeln!(code, "        ];").unwrap();

    // Opcode names
    writeln!(code, "        let opcode_names: HashMap<u32, String> = HashMap::from([").unwrap();
    let mut entries: Vec<(&u32, &String)> = table.opcode_names.iter().collect();
    entries.sort_by_key(|&(k, _)| *k);
    for (id, name) in entries {
        writeln!(code, "            ({}, {:?}.to_string()),", id, name).unwrap();
    }
    writeln!(code, "        ]);").unwrap();

    writeln!(code, "        decoder_tables.insert({:?}.to_string(), DecoderTable::new(bytes, opcode_names));", slot_name).unwrap();
    writeln!(code, "    }}").unwrap();
}
